use regex::Regex;
use std::collections::HashMap;

fn solve(code: Vec<String>, businessLine: Vec<String>, isActive: Vec<bool>) -> Vec<String> {
    let allowed_business = ["electronics", "grocery", "pharmacy", "restaurant"];
    let business_order: HashMap<&str, usize> = allowed_business
        .iter()
        .enumerate()
        .map(|(i, &s)| (s, i))
        .collect();

    let regex = Regex::new(r"^\w+$").unwrap();

    let mut valid = Vec::new();
    for i in 0..code.len() {
        let c = &code[i];
        let b = &businessLine[i];
        let a = isActive[i];

        if c.is_empty() {
            continue;
        }
        if !regex.is_match(c) {
            continue;
        }
        if !allowed_business.contains(&b) {
            continue;
        }
        if !a {
            continue;
        }
        valid.push((b.clone(), c.clone()));
    }

    valid.sort_by(|a, b| {
        let a_order = business_order.get(a.0.as_str()).unwrap();
        let b_order = business_order.get(b.0.as_str()).unwrap();
        a_order.cmp(b_order)
    });

    valid.into_iter().map(|(_, c)| c).collect()
}
